// // This is a 3-input, 6-to-1 demultiplexer with 32-bit wide inputs. It selects one of the three inputs (a0, a1, a2) to output based on a 6-bit selection address (sel_addr). If sel_addr does not match the specified values (6'b110000 for a0, 6'b110001 for a1, and 6'b110010 for a2), it outputs the corresponding input; otherwise, it outputs a default value of zero.
module top_module(a0,a1,a2,sel_addr,y);input [31:0] a0,a1,a2;
	input [5:0] sel_addr;

	output [31:0] y;

	reg [31:0] y;

	always @ *
	begin
		case (sel_addr)
			6'b110000: y = a0; 
			6'b110001: y = a1; 
			6'b110010: y = a2; 
			default: y = 0;
		endcase
	end
endmodule
